sql:
SELECT name 
FROM players 
WHERE playerID = '1';

SELECT playerID
FROM draft_picks
WHERE yearID = 1972;

SELECT AVG(c.salary) AS average_salary
FROM contracts c
JOIN awards a ON c.playerID = a.playerID;

external_knowledge:
- 'Prestigious awards' refers to 'Cy Young' or 'MVP' awards; 
- 'winning streak' means the 'result' in the 'game_logs' table is 'win'; 
- 'lucrative average salaries' means average salaries greater than 0.

- 'MVP' stands for 'Most Valuable Player', an award given to the most outstanding player in a particular season or game; 
- 'Cy Young' is an award given to the best pitcher in each league; 
- 'award-winning sports stars' refers to players who have won awards for their achievements in sports.

